const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: "quote"; items: Item[] }>;
};

type QuoteResult = { premium: number };

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const formsComponentBlock = (items: Item[]): boolean =>
  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === items[0].type);

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);

const groupByType = (items: Item[]): Item[][] => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const existing = groups.get(item.type);
    if (existing) existing.push(item);
    else groups.set(item.type, [item]);
  }
  return [...groups.values()];
};

const basePremiumForGroup = (group: Item[]): number =>
  formsComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);

const basePremiumFor = (items: Item[]): number =>
  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);

const quotePremium = (items: Item[]): QuoteResult => {
  const base = basePremiumFor(items);
  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
};

export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map((step) => quotePremium(step.items));
  return { results };
};

