import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Simplest cases ===
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // === Base premiums for main items ===
  it("single sword (plain, newcomer, no previous contract) → 100 base + 10 first + 5 fee = 115 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (plain, newcomer) → 60 base + 6 first + 5 fee = 71 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (plain, newcomer) → 80 base + 8 first + 5 fee = 93 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (plain, newcomer) → 40 base + 4 first + 5 fee = 49 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // === Components ===
  it("2 runes → 50 G base premium → 50 + 5 first + 5 fee = 60 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block applies) → 60 + 6 first + 5 fee = 71 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base premium (no block) → 100 + 10 first + 5 fee = 115 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base premium (no block) → 175 + 17.5 first + 5 fee = 197.5 → rounded up to 198 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // === Alike components ===
  it("2 runes + 1 moonstone → 75 G base premium (no block: different types) → 88 G total", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base (two blocks) → 120 + 12 first + 5 fee = 137 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // === Item-specific modifiers ===
  it("cursed sword (steel, ench 3, newcomer) → 100 base + 50 curse + 10 first + 5 fee = 165 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with enchantment 5 (newcomer) → 100 + 30 high-ench + 10 first + 5 fee = 145 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge: 100 + 10 first + 5 fee = 115 G");
  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges: 100 + 50 + 30 + 18 first + 5 fee = 203 G");

  // === Policy-wide modifiers ===
  it.todo("loyalty discount — customer with exactly 2 years → 20% off policy total");
  it.todo("loyalty discount does not apply for 1-year customer");
  it.todo("follow-up contract — second quote receives 15% discount on policy total");

  // === Modifier scope on multi-item policies ===
  it.todo("policy with cursed sword + plain amulet → 100 + 60 + 50 curse (item-specific) = 210 before policy-wide and fee");

  // === Rounding ===
  it.todo("premium that yields 197.5 G → rounded up to 198 G (MHPCO's favor)");
  it.todo("payout that yields 350.5 G → rounded down to 350 G (MHPCO's favor)");

  // === Claim processing — basic ===
  it.todo("standard reimbursement: regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("standard reimbursement: rune (insurance 250 G), damage 200 G → payout 100 G");

  // === Claim processing — special clauses ===
  it.todo("high enchantment (≥8) damage at 50%: sword ench 8, damage 1000 G → 500 - 100 deductible = 400 G");
  it.todo("dragon material full reimbursement: dragon sword ench 5, damage 800 G → 800 - 100 = 700 G");
  it.todo("dragon material + ench 9: 50% rule wins then deductible: 500 - 100 = 400 G");
  it.todo("dragon material + ench 8 (boundary): 50% then deductible: 500 - 100 = 400 G");
  it.todo("steel sword ench 9, damage 1000 G → high-ench: 500 - 100 = 400 G");

  // === Deductible per damage event ===
  it.todo("dragon attack on sword (500 G) and amulet (300 G) → 600 G payout (deductible applies once per damaged item)");

  // === Multiple items of the same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack on two swords → each damage entry treated separately with own deductible");
  it.todo("more damage entries of a type than policy covers → CLI rejects with non-zero exit");

  // === Cap exhaustion ===
  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword premium with modifiers doesn't raise cap (cap based on unmodified insurance value)");
  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 G; block affects premium, not insurance sum");
  it.todo("sword (cap 2000 G), first claim 1500 → payout 1400, remaining 600");
  it.todo("sword (cap 2000 G), second claim 1500 → payout 600, remaining 0");

  // === Error cases ===
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
  it.todo("claim references item not in policy → CLI exits non-zero with error on stderr");
  it.todo("claim with negative damage amount → CLI exits non-zero with error on stderr");

  // === Integration examples ===
  it.todo("integration: newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("integration: 3-year customer's second quote, cursed sword (steel, ench 7) → 160 G");
});

