  it.todo("dragon material + ench 9: 50% rule wins then deductible: 500 - 100 = 400 G");
  it.todo("dragon material + ench 8 (boundary): 50% then deductible: 500 - 100 = 400 G");
  it.todo("steel sword ench 9, damage 1000 G → high-ench: 500 - 100 = 400 G");

  // === Deductible per damage event ===
  it.todo("dragon attack on sword (500 G) and amulet (300 G) → 600 G payout (deductible applies once per damaged item)");

  // === Multiple items of the same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack on two swords → each damage entry treated separately with own deductible");
  it.todo("more damage entries of a type than policy covers → CLI rejects with non-zero exit");

  // === Cap exhaustion ===
  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword premium with modifiers doesn't raise cap (cap based on unmodified insurance value)");
  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 G; block affects premium, not insurance sum");
  it.todo("sword (cap 2000 G), first claim 1500 → payout 1400, remaining 600");
  it.todo("sword (cap 2000 G), second claim 1500 → payout 600, remaining 0");

  // === Error cases ===
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
  it.todo("claim references item not in policy → CLI exits non-zero with error on stderr");
  it.todo("claim with negative damage amount → CLI exits non-zero with error on stderr");

  // === Integration examples ===
  it.todo("integration: newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("integration: 3-year customer's second quote, cursed sword (steel, ench 7) → 160 G");
});

