type ClaimStep = { op: "claim"; policy: number; incident: Incident };
type Step = QuoteStep | ClaimStep;

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };
type StepResult = QuoteResult | ClaimResult;

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);

const groupByType = (items: Item[]): Item[][] =>
  Object.values(Object.groupBy(items, (item) => item.type));

const basePremiumForGroup = (group: Item[]): number =>
  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);

const basePremiumFor = (items: Item[]): number =>
  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);

type SurchargeRule = { rate: number; applies: (item: Item) => boolean };

const SURCHARGE_RULES: SurchargeRule[] = [
  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
  {
    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
  },
];

const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
  items.reduce(
    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
    0,
  );

const surchargesFor = (items: Item[]): number =>
  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);

type Customer = { yearsWithMHPCO: number };
type PolicyContext = { customer: Customer; isFollowUp: boolean };

type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };

const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
  {
    rate: LOYALTY_DISCOUNT_RATE,
    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
  },
  {
    rate: FOLLOW_UP_DISCOUNT_RATE,
    applies: ({ isFollowUp }) => isFollowUp,
  },
];

const policyDiscountsFor = (base: number, context: PolicyContext): number =>
  POLICY_DISCOUNT_RULES.reduce(
    (total, rule) => (rule.applies(context) ? total + base * rule.rate : total),
    0,
  );

const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
  const base = basePremiumFor(items);
  const surcharges = surchargesFor(items);
  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
  return {
    premium: Math.ceil(base + surcharges - discounts + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
  };
};

const isFollowUpStep = (index: number): boolean => index > 0;

type Policy = { items: Item[]; remainingCap: number };

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

const createPolicy = (items: Item[]): Policy => ({
  items,
  remainingCap: CAP_MULTIPLIER * insuranceSumFor(items),
});

const payoutForDamage = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const payout = incident.damages.reduce((sum, damage) => sum + payoutForDamage(damage), 0);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  const results: StepResult[] = steps.map((step, index) => {
    if (step.op === "quote") {
      policies[index] = createPolicy(step.items);
      return quotePremium(step.items, customer, isFollowUpStep(index));
    }
    return processClaim(policies[step.policy], step.incident);
  });
  return { results };
};

